import React, { Component } from "react";
import { AppBar, Toolbar, IconButton, Typography, Drawer, List, ListItem, ListItemText, Box } from "@mui/material";


const navItems = ["About", "Skills", "Experience", "Projects", "Education", "Contact"];

class Layout extends Component {
  constructor(props) {
    super(props);
    this.state = {
      sidebarOpen: false,
      selectedContent: "Welcome to My Portfolio"
    };
  }

  toggleSidebar = (open) => {
    this.setState({ sidebarOpen: open });
  };

  handleNavClick = (text) => {
    this.setState({ selectedContent: text, sidebarOpen: false });
  };

  render() {
    const { children, width } = this.props;
    const { sidebarOpen, selectedContent } = this.state;
    const isMobile = width === "xs" || width === "sm";

    return (
      <>
        <AppBar position="static">
          <Toolbar>
            {isMobile && (
              <IconButton edge="start" color="inherit" aria-label="menu" onClick={() => this.toggleSidebar(true)}>
                <MenuIcon />
              </IconButton>
            )}
            <Typography variant="h6" sx={{ flexGrow: 1 }}>
              My Portfolio
            </Typography>
            <Box sx={{ display: { xs: "none", md: "flex" } }}>
              {navItems.map((item) => (
                <Typography key={item} sx={{ margin: "0 10px", cursor: "pointer" }}>
                  {item}
                </Typography>
              ))}
            </Box>
          </Toolbar>
        </AppBar>
        <Drawer anchor="left" open={sidebarOpen} onClose={() => this.toggleSidebar(false)}>
          <List>
            {navItems.map((text) => (
              <ListItem button key={text} onClick={() => this.handleNavClick(text)}>
                <ListItemText primary={text} />
              </ListItem>
            ))}
          </List>
        </Drawer>
        <Box sx={{ padding: 2 }}>{children || <Typography>{selectedContent}</Typography>}</Box>
      </>
    );
  }
}

export default withMediaQuery()(Layout);
